--
-- Table structure for table `caipiao_member`
--

DROP TABLE IF EXISTS `caipiao_member`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `caipiao_member` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `parentid` int(11) NOT NULL DEFAULT '0' COMMENT 'ID cấp trên',
  `fanshuifee` decimal(5,2) DEFAULT '0.00' COMMENT 'Tỷ lệ hoàn trả đại lý %',
  `groupid` smallint(6) NOT NULL DEFAULT '1',
  `jinjijilu` tinyint(2) DEFAULT '1' COMMENT 'Bản ghi thăng cấp',
  `username` char(60) NOT NULL,
  `nickname` varchar(20) NOT NULL COMMENT 'Biệt danh',
  `proxy` tinyint(4) NOT NULL COMMENT '1-đại lý, 0-thường',
  `isnb` tinyint(4) NOT NULL COMMENT '1-nội bộ, 0-thường',
  `email` char(60) NOT NULL,
  `phone` char(12) NOT NULL COMMENT 'Số điện thoại',
  `userbankname` varchar(30) NOT NULL COMMENT 'Họ tên thật',
  `password` varchar(255) NOT NULL,
  `tradepassword` char(32) NOT NULL DEFAULT 'd93a5def7511da3d0f2d171d9c344e91' COMMENT 'Mật khẩu giao dịch',
  `sex` tinyint(3) DEFAULT '1' COMMENT 'Giới tính',
  `balance` decimal(14,3) NOT NULL COMMENT 'Số dư',
  `xima` decimal(14,3) NOT NULL COMMENT 'Số dư rửa mã',
  `fandian` varchar(255) NOT NULL DEFAULT '' COMMENT 'Hoàn cược hội viên',
  `tel` char(20) NOT NULL,
  `face` varchar(255) DEFAULT NULL,
  `loginip` char(20) NOT NULL,
  `device_id` varchar(128) DEFAULT NULL COMMENT 'ID thiết bị',
  `last_ip` varchar(45) DEFAULT NULL COMMENT 'IP đăng nhập cuối',
  `iparea` char(20) NOT NULL,
  `regtime` int(11) NOT NULL COMMENT 'Thời gian đăng ký',
  `regip` char(20) NOT NULL COMMENT 'IP đăng ký',
  `source` varchar(30) NOT NULL COMMENT 'Nguồn đăng ký',
  `logintime` int(11) NOT NULL,
  `loginsource` char(20) NOT NULL COMMENT 'pc, mobile',
  `onlinetime` int(11) NOT NULL COMMENT 'Thời gian online',
  `islock` tinyint(1) NOT NULL DEFAULT '0',
  `is_robot` tinyint(1) DEFAULT '0',
  `birthday` date NOT NULL,
  `record` decimal(14,2) NOT NULL,
  `is_rebet` int(1) DEFAULT NULL,
  `yebmoney` decimal(14,2) NOT NULL DEFAULT '0.00' COMMENT 'Số dư tiết kiệm',
  `money` decimal(14,2) NOT NULL DEFAULT '0.00' COMMENT 'Số tiền',
  `yebtime` int(11) NOT NULL COMMENT 'Thời gian',
  `yeblixi` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT 'Lãi suất tiết kiệm',
  `dyebmoney` decimal(14,2) NOT NULL DEFAULT '0.00' COMMENT 'Số dư đóng băng',
  `ngbalance` decimal(14,2) NOT NULL COMMENT 'Số dư NG',
  `google_secret` varchar(32) DEFAULT '' COMMENT 'Mã bí mật Google',
  `google_bind` tinyint(1) DEFAULT '0' COMMENT 'Đã liên kết Google',
  `security_question` varchar(100) DEFAULT '' COMMENT 'Câu hỏi bảo mật',
  `security_answer` varchar(100) DEFAULT '' COMMENT 'Câu trả lời bảo mật',
  `settings` json DEFAULT NULL COMMENT 'Cài đặt người dùng',
  PRIMARY KEY (`id`),
  KEY `groupid` (`groupid`),
  KEY `onlinetime` (`onlinetime`),
  KEY `isnb` (`isnb`),
  KEY `proxy` (`proxy`),
  KEY `username` (`username`),
  KEY `idx_device_id` (`device_id`),
  KEY `idx_is_robot` (`is_robot`)
) ENGINE=InnoDB AUTO_INCREMENT=19132 DEFAULT CHARSET=utf8 ROW_FORMAT=DYNAMIC;
/*!40101 SET character_set_client = @saved_cs_client */;

